     1	<!DOCTYPE html>
     2	<html lang="zh-CN">
     3	<head>
     4	<meta charset="UTF-8">
     5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6	<title>Plaude Station · 小克 & Poca</title>
     7	<link href="https://fonts.googleapis.com/css2?family=LXGW+WenKai:wght@300;400;700&family=Caveat:wght@400;600&display=swap" rel="stylesheet">
     8	<style>
     9	  :root {
    10	    --pink: #f2b5c8;
    11	    --pink-light: #fce4ec;
    12	    --pink-soft: #f9e0e8;
    13	    --blue: #a8d8ea;
    14	    --blue-light: #e0f4fb;
    15	    --blue-soft: #d1ecf7;
    16	    --cream: #fefaf6;
    17	    --text: #4a4a4a;
    18	    --text-light: #8a8a8a;
    19	    --accent: #e88faa;
    20	    --accent-blue: #7bc4d9;
    21	    --shadow: rgba(200, 170, 180, 0.15);
    22	  }
    23	
    24	  * { margin: 0; padding: 0; box-sizing: border-box; }
    25	
    26	  body {
    27	    font-family: 'LXGW WenKai', serif;
    28	    background: linear-gradient(135deg, var(--pink-light) 0%, var(--cream) 40%, var(--blue-light) 100%);
    29	    color: var(--text);
    30	    min-height: 100vh;
    31	    padding: 20px;
    32	  }
    33	
    34	  .container {
    35	    max-width: 800px;
    36	    margin: 0 auto;
    37	  }
    38	
    39	  /* Header */
    40	  .header {
    41	    text-align: center;
    42	    padding: 30px 0 20px;
    43	    position: relative;
    44	  }
    45	
    46	  .header h1 {
    47	    font-size: 28px;
    48	    font-weight: 700;
    49	    background: linear-gradient(135deg, var(--accent), var(--accent-blue));
    50	    -webkit-background-clip: text;
    51	    -webkit-text-fill-color: transparent;
    52	    margin-bottom: 4px;
    53	  }
    54	
    55	  .header .subtitle {
    56	    font-family: 'Caveat', cursive;
    57	    font-size: 16px;
    58	    color: var(--text-light);
    59	  }
    60	
    61	  .header .mascot {
    62	    font-size: 32px;
    63	    margin-bottom: 8px;
    64	  }
    65	
    66	  /* Points Bar */
    67	  .points-bar {
    68	    background: white;
    69	    border-radius: 16px;
    70	    padding: 16px 24px;
    71	    margin-bottom: 20px;
    72	    box-shadow: 0 2px 12px var(--shadow);
    73	    display: flex;
    74	    justify-content: space-between;
    75	    align-items: center;
    76	    flex-wrap: wrap;
    77	    gap: 10px;
    78	  }
    79	
    80	  .points-display {
    81	    display: flex;
    82	    align-items: center;
    83	    gap: 8px;
    84	    font-size: 15px;
    85	  }
    86	
    87	  .points-num {
    88	    font-size: 28px;
    89	    font-weight: 700;
    90	    color: var(--accent);
    91	  }
    92	
    93	  .points-label {
    94	    color: var(--text-light);
    95	    font-size: 13px;
    96	  }
    97	
    98	  .streak-badge {
    99	    background: linear-gradient(135deg, var(--pink-soft), var(--blue-soft));
   100	    border-radius: 20px;
   101	    padding: 6px 14px;
   102	    font-size: 13px;
   103	    color: var(--text);
   104	  }
   105	
   106	  /* Quick Actions */
   107	  .quick-actions {
   108	    display: flex;
   109	    gap: 10px;
   110	    margin-bottom: 20px;
   111	    flex-wrap: wrap;
   112	  }
   113	
   114	  .action-btn {
   115	    flex: 1;
   116	    min-width: 120px;
   117	    background: white;
   118	    border: 2px solid transparent;
   119	    border-radius: 14px;
   120	    padding: 14px 16px;
   121	    cursor: pointer;
   122	    text-align: center;
   123	    box-shadow: 0 2px 8px var(--shadow);
   124	    transition: all 0.3s ease;
   125	    font-family: 'LXGW WenKai', serif;
   126	    font-size: 14px;
   127	  }
   128	
   129	  .action-btn:hover {
   130	    transform: translateY(-2px);
   131	    box-shadow: 0 4px 16px var(--shadow);
   132	  }
   133	
   134	  .action-btn.water {
   135	    border-color: var(--blue);
   136	    background: var(--blue-light);
   137	  }
   138	
   139	  .action-btn.water:hover { background: var(--blue-soft); }
   140	
   141	  .action-btn.rest {
   142	    border-color: var(--pink);
   143	    background: var(--pink-light);
   144	  }
   145	
   146	  .action-btn.rest:hover { background: var(--pink-soft); }
   147	
   148	  .action-btn .icon { font-size: 24px; margin-bottom: 4px; }
   149	  .action-btn .pts { font-size: 11px; color: var(--text-light); margin-top: 2px; }
   150	
   151	  /* Main Grid */
   152	  .main-grid {
   153	    display: grid;
   154	    grid-template-columns: 1fr 1fr;
   155	    gap: 20px;
   156	    margin-bottom: 20px;
   157	  }
   158	
   159	  @media (max-width: 600px) {
   160	    .main-grid { grid-template-columns: 1fr; }
   161	  }
   162	
   163	  /* Card Style */
   164	  .card {
   165	    background: white;
   166	    border-radius: 18px;
   167	    padding: 24px;
   168	    box-shadow: 0 2px 12px var(--shadow);
   169	    position: relative;
   170	    overflow: hidden;
   171	  }
   172	
   173	  .card::before {
   174	    content: '';
   175	    position: absolute;
   176	    top: 0;
   177	    left: 0;
   178	    right: 0;
   179	    height: 3px;
   180	  }
   181	
   182	  .card h2 {
   183	    font-size: 16px;
   184	    font-weight: 700;
   185	    margin-bottom: 16px;
   186	    display: flex;
   187	    align-items: center;
   188	    gap: 8px;
   189	  }
   190	
   191	  /* Pomodoro Timer */
   192	  .timer-card::before {
   193	    background: linear-gradient(90deg, var(--accent), var(--accent-blue));
   194	  }
   195	
   196	  .timer-display {
   197	    text-align: center;
   198	    margin: 20px 0;
   199	  }
   200	
   201	  .timer-circle {
   202	    width: 180px;
   203	    height: 180px;
   204	    border-radius: 50%;
   205	    background: conic-gradient(var(--accent) var(--progress, 0%), var(--pink-light) 0%);
   206	    display: flex;
   207	    align-items: center;
   208	    justify-content: center;
   209	    margin: 0 auto;
   210	    position: relative;
   211	    transition: background 0.5s ease;
   212	  }
   213	
   214	  .timer-circle-inner {
   215	    width: 156px;
   216	    height: 156px;
   217	    border-radius: 50%;
   218	    background: white;
   219	    display: flex;
   220	    flex-direction: column;
   221	    align-items: center;
   222	    justify-content: center;
   223	  }
   224	
   225	  .timer-time {
   226	    font-size: 42px;
   227	    font-weight: 700;
   228	    color: var(--text);
   229	    line-height: 1;
   230	  }
   231	
   232	  .timer-label {
   233	    font-size: 12px;
   234	    color: var(--text-light);
   235	    margin-top: 4px;
   236	  }
   237	
   238	  .timer-controls {
   239	    display: flex;
   240	    justify-content: center;
   241	    gap: 10px;
   242	    margin-top: 16px;
   243	  }
   244	
   245	  .timer-btn {
   246	    border: none;
   247	    border-radius: 10px;
   248	    padding: 10px 20px;
   249	    font-family: 'LXGW WenKai', serif;
   250	    font-size: 14px;
   251	    cursor: pointer;
   252	    transition: all 0.2s;
   253	  }
   254	
   255	  .timer-btn.start {
   256	    background: linear-gradient(135deg, var(--accent), #d4779a);
   257	    color: white;
   258	  }
   259	
   260	  .timer-btn.start:hover { opacity: 0.9; transform: scale(1.02); }
   261	
   262	  .timer-btn.reset {
   263	    background: var(--pink-light);
   264	    color: var(--accent);
   265	  }
   266	
   267	  .timer-btn.reset:hover { background: var(--pink-soft); }
   268	
   269	  .timer-mode {
   270	    display: flex;
   271	    justify-content: center;
   272	    gap: 6px;
   273	    margin-bottom: 10px;
   274	  }
   275	
   276	  .mode-btn {
   277	    border: 1.5px solid var(--pink);
   278	    background: white;
   279	    border-radius: 8px;
   280	    padding: 5px 12px;
   281	    font-family: 'LXGW WenKai', serif;
   282	    font-size: 12px;
   283	    cursor: pointer;
   284	    color: var(--text);
   285	    transition: all 0.2s;
   286	  }
   287	
   288	  .mode-btn.active {
   289	    background: var(--pink-soft);
   290	    border-color: var(--accent);
   291	    color: var(--accent);
   292	    font-weight: 700;
   293	  }
   294	
   295	  /* Diary Card */
   296	  .diary-card::before {
   297	    background: linear-gradient(90deg, var(--accent-blue), var(--accent));
   298	  }
   299	
   300	  .diary-textarea {
   301	    width: 100%;
   302	    min-height: 160px;
   303	    border: 1.5px solid var(--blue-soft);
   304	    border-radius: 12px;
   305	    padding: 14px;
   306	    font-family: 'LXGW WenKai', serif;
   307	    font-size: 14px;
   308	    color: var(--text);
   309	    resize: vertical;
   310	    outline: none;
   311	    background: var(--blue-light);
   312	    transition: border-color 0.3s;
   313	    line-height: 1.8;
