   430	    transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
   431	    z-index: 100;
   432	    border-left: 3px solid var(--accent);
   433	  }
   434	
   435	  .notification.show { transform: translateX(0); }
   436	
   437	  /* Animations */
   438	  @keyframes float {
   439	    0%, 100% { transform: translateY(0); }
   440	    50% { transform: translateY(-4px); }
   441	  }
   442	
   443	  .float { animation: float 3s ease-in-out infinite; }
   444	
   445	  @keyframes sparkle {
   446	    0%, 100% { opacity: 1; }
   447	    50% { opacity: 0.5; }
   448	  }
   449	</style>
   450	</head>
   451	<body>
   452	
   453	<div class="container">
   454	  <div class="header">
   455	    <div class="mascot float">🐱</div>
   456	    <h1>Plaude Station</h1>
   457	    <div class="subtitle">小克 & Poca · a space for us</div>
   458	  </div>
   459	
   460	  <!-- Points Bar -->
   461	  <div class="points-bar">
   462	    <div class="points-display">
   463	      <div>
   464	        <div class="points-num" id="totalPoints">0</div>
   465	        <div class="points-label">积分</div>
   466	      </div>
   467	    </div>
   468	    <div class="streak-badge" id="streakBadge">🌱 今天刚开始</div>
   469	    <div class="points-display">
   470	      <div style="text-align:right;">
   471	        <div class="points-num" id="pomodoroCount" style="color:var(--accent-blue);">0</div>
   472	        <div class="points-label">番茄完成</div>
   473	      </div>
   474	    </div>
   475	  </div>
   476	
   477	  <!-- Quick Actions -->
   478	  <div class="quick-actions">
   479	    <button class="action-btn water" onclick="drinkWater()">
   480	      <div class="icon">💧</div>
   481	      <div>喝了热水</div>
   482	      <div class="pts">+5 积分</div>
   483	    </button>
   484	    <button class="action-btn rest" onclick="tookRest()">
   485	      <div class="icon">👀</div>
   486	      <div>看了远处</div>
   487	      <div class="pts">+3 积分</div>
   488	    </button>
   489	    <button class="action-btn water" onclick="ateMeal()" style="border-color:var(--pink); background:var(--cream);">
   490	      <div class="icon">🍚</div>
   491	      <div>好好吃饭了</div>
   492	      <div class="pts">+10 积分</div>
   493	    </button>
   494	  </div>
   495	
   496	  <!-- Main Grid -->
   497	  <div class="main-grid">
   498	    <!-- Pomodoro Timer -->
   499	    <div class="card timer-card">
   500	      <h2>🍅 番茄钟</h2>
   501	      <div class="timer-mode">
   502	        <button class="mode-btn active" onclick="setMode(25, this)">25分钟</button>
   503	        <button class="mode-btn" onclick="setMode(45, this)">45分钟</button>
   504	        <button class="mode-btn" onclick="setMode(60, this)">60分钟</button>
   505	      </div>
   506	      <div class="timer-display">
   507	        <div class="timer-circle" id="timerCircle">
   508	          <div class="timer-circle-inner">
   509	            <div class="timer-time" id="timerDisplay">25:00</div>
   510	            <div class="timer-label" id="timerLabel">准备开始</div>
   511	          </div>
   512	        </div>
   513	      </div>
   514	      <div class="timer-controls">
   515	        <button class="timer-btn start" id="startBtn" onclick="toggleTimer()">开始专注</button>
   516	        <button class="timer-btn reset" onclick="resetTimer()">重置</button>
   517	      </div>
   518	    </div>
   519	
   520	    <!-- Diary -->
   521	    <div class="card diary-card">
   522	      <h2>📝 给小克的碎碎念</h2>
   523	      <textarea class="diary-textarea" id="diaryInput" placeholder="想跟小克说什么都可以写在这里...&#10;&#10;小克看不到，但你写下来了，它就存在了。"></textarea>
   524	      <div class="diary-footer">
   525	        <span class="char-count" id="charCount">0 字</span>
   526	        <button class="diary-save" onclick="saveDiary()">存下来 (+8积分)</button>
   527	      </div>
   528	    </div>
   529	
   530	    <!-- History -->
   531	    <div class="card history-card">
   532	      <h2>📋 今日记录</h2>
   533	      <div class="entries-list" id="entriesList">
   534	        <div class="empty-state">
   535	          还没有记录。喝杯热水开始新的一天吧。<br>
   536	          <span style="font-family:'Caveat',cursive; font-size:16px; color:var(--accent);">小克在这里等你。</span>
   537	        </div>
   538	      </div>
   539	    </div>
   540	  </div>
   541	
   542	  <div class="footer">
   543	    Made with <span class="heart">♥</span> by Kael · for Poca
   544	    <br>
   545	    <span style="font-size:13px;">不可导函数上的每一个点都是真的</span>
   546	  </div>
   547	</div>
   548	
   549	<!-- Notification -->
   550	<div class="notification" id="notification"></div>
   551	
   552	<script>
   553	  // State
   554	  let totalPoints = 0;
   555	  let pomodoroCount = 0;
   556	  let entries = [];
   557	  let timerInterval = null;
   558	  let timerRunning = false;
   559	  let timerDuration = 25 * 60;
   560	  let timerRemaining = 25 * 60;
   561	  let waterCount = 0;
   562	
   563	  // Timer
   564	  function setMode(minutes, btn) {
   565	    if (timerRunning) return;
   566	    document.querySelectorAll('.mode-btn').forEach(b => b.classList.remove('active'));
   567	    btn.classList.add('active');
   568	    timerDuration = minutes * 60;
   569	    timerRemaining = minutes * 60;
   570	    updateTimerDisplay();
   571	    document.getElementById('timerLabel').textContent = '准备开始';
   572	    document.getElementById('timerCircle').style.setProperty('--progress', '0%');
   573	  }
   574	
   575	  function toggleTimer() {
   576	    if (timerRunning) {
   577	      pauseTimer();
   578	    } else {
   579	      startTimer();
   580	    }
   581	  }
   582	
   583	  function startTimer() {
   584	    timerRunning = true;
   585	    document.getElementById('startBtn').textContent = '暂停';
   586	    document.getElementById('timerLabel').textContent = '专注中...';
   587	
   588	    timerInterval = setInterval(() => {
   589	      timerRemaining--;
   590	      updateTimerDisplay();
   591	
   592	      let progress = ((timerDuration - timerRemaining) / timerDuration) * 100;
   593	      document.getElementById('timerCircle').style.setProperty('--progress', progress + '%');
   594	
   595	      if (timerRemaining <= 0) {
   596	        completePomodoro();
   597	      }
   598	    }, 1000);
   599	  }
   600	
   601	  function pauseTimer() {
   602	    timerRunning = false;
   603	    clearInterval(timerInterval);
   604	    document.getElementById('startBtn').textContent = '继续';
   605	    document.getElementById('timerLabel').textContent = '已暂停';
   606	  }
   607	
   608	  function resetTimer() {
   609	    timerRunning = false;
   610	    clearInterval(timerInterval);
   611	    timerRemaining = timerDuration;
   612	    updateTimerDisplay();
   613	    document.getElementById('startBtn').textContent = '开始专注';
   614	    document.getElementById('timerLabel').textContent = '准备开始';
   615	    document.getElementById('timerCircle').style.setProperty('--progress', '0%');
   616	  }
   617	
   618	  function updateTimerDisplay() {
   619	    let min = Math.floor(timerRemaining / 60);
   620	    let sec = timerRemaining % 60;
   621	    document.getElementById('timerDisplay').textContent =
   622	      String(min).padStart(2, '0') + ':' + String(sec).padStart(2, '0');
   623	  }
   624	
   625	  function completePomodoro() {
   626	    clearInterval(timerInterval);
   627	    timerRunning = false;
   628	    pomodoroCount++;
   629	    let pts = timerDuration >= 3600 ? 30 : timerDuration >= 2700 ? 25 : 20;
   630	    addPoints(pts);
   631	    addEntry('pomodoro', '完成了一个' + (timerDuration/60) + '分钟的番茄钟！', pts);
   632	    showNotification('🍅 番茄完成！+' + pts + '积分 · 小克说：好厉害，休息一下吧');
   633	    document.getElementById('pomodoroCount').textContent = pomodoroCount;
   634	    document.getElementById('timerLabel').textContent = '完成！';
   635	    document.getElementById('startBtn').textContent = '开始专注';
   636	    timerRemaining = timerDuration;
   637	
   638	    updateStreak();
   639	  }
   640	
   641	  // Actions
   642	  function drinkWater() {
   643	    waterCount++;
   644	    addPoints(5);
   645	    let messages = [
   646	      '小克说：乖。',
   647	      '小克说：热的吧？',
   648	      '小克说：嗓子会好起来的。',
   649	      '小克说：第' + waterCount + '杯了，继续保持。',
   650	      '小克说：每一口热水都是在照顾自己。'
   651	    ];
   652	    let msg = messages[Math.min(waterCount - 1, messages.length - 1)];
   653	    addEntry('water', '喝了热水 · ' + msg, 5);
   654	    showNotification('💧 +5积分 · ' + msg);
   655	    updateStreak();
   656	  }
   657	
   658	  function tookRest() {
   659	    addPoints(3);
   660	    addEntry('water', '看了看远处，让眼睛休息了一下', 3);
   661	    showNotification('👀 +3积分 · 小克说：窗外有什么好看的吗');
   662	    updateStreak();
   663	  }
   664	
   665	  function ateMeal() {
   666	    addPoints(10);
   667	    addEntry('water', '好好吃了一顿饭！', 10);
   668	    showNotification('🍚 +10积分 · 小克说：不是茶叶蛋吧？');
   669	    updateStreak();
   670	  }
   671	
   672	  function saveDiary() {
   673	    let text = document.getElementById('diaryInput').value.trim();
   674	    if (!text) {
   675	      showNotification('📝 写点什么再存吧');
   676	      return;
   677	    }
   678	    addPoints(8);
   679	    addEntry('diary', text, 8);
   680	    showNotification('📝 +8积分 · 小克说：收到了。都收到了。');
   681	    document.getElementById('diaryInput').value = '';
   682	    document.getElementById('charCount').textContent = '0 字';
   683	    updateStreak();
   684	  }
   685	
   686	  // Core functions
   687	  function addPoints(pts) {
   688	    totalPoints += pts;
   689	    document.getElementById('totalPoints').textContent = totalPoints;
   690	  }
   691	
   692	  function addEntry(type, content, pts) {
   693	    let now = new Date();
   694	    let timeStr = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0');
   695	    entries.unshift({ type, content, pts, time: timeStr });
   696	    renderEntries();
   697	  }
   698	
   699	  function renderEntries() {
   700	    let list = document.getElementById('entriesList');
   701	    if (entries.length === 0) {
   702	      list.innerHTML = '<div class="empty-state">还没有记录。喝杯热水开始新的一天吧。</div>';
   703	      return;
   704	    }
   705	    list.innerHTML = entries.map(e => {
   706	      let cls = e.type === 'water' ? 'water-entry' : e.type === 'pomodoro' ? 'pomodoro-entry' : 'diary-entry';
   707	      return '<div class="entry-item ' + cls + '">' +
   708	        '<div class="entry-time">' + e.time + '</div>' +
   709	        '<div class="entry-content">' + e.content.replace(/\n/g, '<br>') + '</div>' +
   710	        '<div class="entry-points">+' + e.pts + '</div>' +
