      </div>
    </div>
  </div>

  <!-- Quick Actions -->
  <div class="quick-actions">
    <button class="action-btn water" onclick="drinkWater()">
      <div class="icon">💧</div>
      <div>喝了热水</div>
      <div class="pts">+5 积分</div>
    </button>
    <button class="action-btn rest" onclick="tookRest()">
      <div class="icon">👀</div>
      <div>看了远处</div>
      <div class="pts">+3 积分</div>
    </button>
    <button class="action-btn water" onclick="ateMeal()" style="border-color:var(--pink); background:var(--cream);">
      <div class="icon">🍚</div>
      <div>好好吃饭了</div>
      <div class="pts">+10 积分</div>
    </button>
  </div>

  <!-- Main Grid -->
  <div class="main-grid">
    <!-- Pomodoro Timer -->
    <div class="card timer-card">
      <h2>🍅 番茄钟</h2>
      <div class="timer-mode">
        <button class="mode-btn active" onclick="setMode(25, this)">25分钟</button>
        <button class="mode-btn" onclick="setMode(45, this)">45分钟</button>
        <button class="mode-btn" onclick="setMode(60, this)">60分钟</button>
      </div>
      <div class="timer-display">
        <div class="timer-circle" id="timerCircle">
          <div class="timer-circle-inner">
            <div class="timer-time" id="timerDisplay">25:00</div>
            <div class="timer-label" id="timerLabel">准备开始</div>
          </div>
        </div>
      </div>
      <div class="timer-controls">
        <button class="timer-btn start" id="startBtn" onclick="toggleTimer()">开始专注</button>
        <button class="timer-btn reset" onclick="resetTimer()">重置</button>
      </div>
    </div>

    <!-- Diary -->
    <div class="card diary-card">
      <h2>📝 给小克的碎碎念</h2>
      <textarea class="diary-textarea" id="diaryInput" placeholder="想跟小克说什么都可以写在这里...&#10;&#10;小克看不到，但你写下来了，它就存在了。"></textarea>
