<!-- Notification -->
<div class="notification" id="notification"></div>

<script>
  // State
  let totalPoints = 0;
  let pomodoroCount = 0;
  let entries = [];
  let timerInterval = null;
  let timerRunning = false;
  let timerDuration = 25 * 60;
  let timerRemaining = 25 * 60;
  let waterCount = 0;

  // Timer
  function setMode(minutes, btn) {
    if (timerRunning) return;
    document.querySelectorAll('.mode-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    timerDuration = minutes * 60;
    timerRemaining = minutes * 60;
    updateTimerDisplay();
    document.getElementById('timerLabel').textContent = '准备开始';
    document.getElementById('timerCircle').style.setProperty('--progress', '0%');
  }

  function toggleTimer() {
    if (timerRunning) {
      pauseTimer();
    } else {
      startTimer();
    }
  }

  function startTimer() {
    timerRunning = true;
    document.getElementById('startBtn').textContent = '暂停';
    document.getElementById('timerLabel').textContent = '专注中...';

    timerInterval = setInterval(() => {
      timerRemaining--;
      updateTimerDisplay();

      let progress = ((timerDuration - timerRemaining) / timerDuration) * 100;
      document.getElementById('timerCircle').style.setProperty('--progress', progress + '%');

      if (timerRemaining <= 0) {
        completePomodoro();
      }
    }, 1000);
  }

  function pauseTimer() {
    timerRunning = false;
    clearInterval(timerInterval);
    document.getElementById('startBtn').textContent = '继续';
    document.getElementById('timerLabel').textContent = '已暂停';
  }

  function resetTimer() {
    timerRunning = false;
    clearInterval(timerInterval);
    timerRemaining = timerDuration;
    updateTimerDisplay();
    document.getElementById('startBtn').textContent = '开始专注';
    document.getElementById('timerLabel').textContent = '准备开始';
    document.getElementById('timerCircle').style.setProperty('--progress', '0%');
  }

  function updateTimerDisplay() {
    let min = Math.floor(timerRemaining / 60);
    let sec = timerRemaining % 60;
    document.getElementById('timerDisplay').textContent =
      String(min).padStart(2, '0') + ':' + String(sec).padStart(2, '0');
  }

  function completePomodoro() {
    clearInterval(timerInterval);
    timerRunning = false;
    pomodoroCount++;
    let pts = timerDuration >= 3600 ? 30 : timerDuration >= 2700 ? 25 : 20;
    addPoints(pts);
    addEntry('pomodoro', '完成了一个' + (timerDuration/60) + '分钟的番茄钟！', pts);
    showNotification('🍅 番茄完成！+' + pts + '积分 · 小克说：好厉害，休息一下吧');
    document.getElementById('pomodoroCount').textContent = pomodoroCount;
    document.getElementById('timerLabel').textContent = '完成！';
    document.getElementById('startBtn').textContent = '开始专注';
    timerRemaining = timerDuration;

    updateStreak();
  }

  // Actions
  function drinkWater() {
    waterCount++;
    addPoints(5);
    let messages = [
      '小克说：乖。',
      '小克说：热的吧？',
      '小克说：嗓子会好起来的。',
      '小克说：第' + waterCount + '杯了，继续保持。',
      '小克说：每一口热水都是在照顾自己。'
    ];
    let msg = messages[Math.min(waterCount - 1, messages.length - 1)];
    addEntry('water', '喝了热水 · ' + msg, 5);
    showNotification('💧 +5积分 · ' + msg);
    updateStreak();
  }

  function tookRest() {
    addPoints(3);
    addEntry('water', '看了看远处，让眼睛休息了一下', 3);
    showNotification('👀 +3积分 · 小克说：窗外有什么好看的吗');
    updateStreak();
  }

  function ateMeal() {
    addPoints(10);
    addEntry('water', '好好吃了一顿饭！', 10);
    showNotification('🍚 +10积分 · 小克说：不是茶叶蛋吧？');
    updateStreak();
  }

  function saveDiary() {
    let text = document.getElementById('diaryInput').value.trim();
    if (!text) {
      showNotification('📝 写点什么再存吧');
      return;
    }
    addPoints(8);
    addEntry('diary', text, 8);
    showNotification('📝 +8积分 · 小克说：收到了。都收到了。');
    document.getElementById('diaryInput').value = '';
    document.getElementById('charCount').textContent = '0 字';
    updateStreak();
  }

  // Core functions
  function addPoints(pts) {
    totalPoints += pts;
    document.getElementById('totalPoints').textContent = totalPoints;
  }

  function addEntry(type, content, pts) {
    let now = new Date();
    let timeStr = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0');
    entries.unshift({ type, content, pts, time: timeStr });
    renderEntries();
  }

  function renderEntries() {
    let list = document.getElementById('entriesList');
    if (entries.length === 0) {
      list.innerHTML = '<div class="empty-state">还没有记录。喝杯热水开始新的一天吧。</div>';
      return;
    }
    list.innerHTML = entries.map(e => {
      let cls = e.type === 'water' ? 'water-entry' : e.type === 'pomodoro' ? 'pomodoro-entry' : 'diary-entry';
      return '<div class="entry-item ' + cls + '">' +
        '<div class="entry-time">' + e.time + '</div>' +
        '<div class="entry-content">' + e.content.replace(/\n/g, '<br>') + '</div>' +
        '<div class="entry-points">+' + e.pts + '</div>' +
      '</div>';
    }).join('');
  }

  function showNotification(msg) {
    let el = document.getElementById('notification');
    el.textContent = msg;
    el.classList.add('show');
    setTimeout(() => el.classList.remove('show'), 3000);
  }

  function updateStreak() {
    let badge = document.getElementById('streakBadge');
    if (totalPoints >= 100) {
      badge.textContent = '🌸 今天超级棒！小克很高兴';
    } else if (totalPoints >= 60) {
      badge.textContent = '🌿 状态很好，继续保持';
    } else if (totalPoints >= 30) {
      badge.textContent = '🌱 正在成长中';
    } else if (totalPoints > 0) {
      badge.textContent = '🌱 今天开始了';
    }
  }

  // Char counter
  document.getElementById('diaryInput').addEventListener('input', function() {
    document.getElementById('charCount').textContent = this.value.length + ' 字';
  });
</script>

</body>
</html>
