    box-shadow: 0 2px 8px var(--shadow);
    transition: all 0.25s ease;
    font-family: 'LXGW WenKai', serif;
    font-size: 13px;
    color: var(--text);
  }

  .action-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 14px var(--shadow-hover);
    border-color: var(--accent-light);
  }

  .action-btn:active { transform: translateY(0); }

  .action-btn .icon { font-size: 22px; margin-bottom: 3px; }
  .action-btn .pts { font-size: 11px; color: var(--text-light); margin-top: 2px; }

  /* ─── Main Grid ─── */
  .main-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
    margin-bottom: 16px;
  }

  @media (max-width: 640px) {
    .main-grid { grid-template-columns: 1fr; }
  }

  /* ─── Card ─── */
  .card {
    background: var(--card);
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: 0 2px 10px var(--shadow);
    position: relative;
    overflow: hidden;
  }

  .card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 3px;
    background: linear-gradient(90deg, var(--accent), var(--accent-light));
  }

  .card h2 {
    font-size: 15px;
    font-weight: 700;
    margin-bottom: 14px;
    display: flex;
    align-items: center;
    gap: 6px;
  }

  /* ─── Pomodoro ─── */
  .timer-mode {
    display: flex;
    justify-content: center;
    gap: 6px;
    margin-bottom: 12px;
  }

  .mode-btn {
    border: 1.5px solid var(--cream);
    background: var(--card);
    border-radius: 8px;
    padding: 4px 12px;
    font-family: 'LXGW WenKai', serif;
    font-size: 12px;
    cursor: pointer;
    color: var(--text-light);
    transition: all 0.2s;
  }

  .mode-btn.active {
    background: var(--cream-light);
    border-color: var(--accent);
    color: var(--accent);
    font-weight: 700;
  }

  .timer-display { text-align: center; margin: 16px 0; }

  .timer-circle {
    width: 160px;
    height: 160px;
    border-radius: 50%;
    background: conic-gradient(var(--accent) calc(var(--progress, 0) * 1%), var(--cream-light) 0%);
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto;
    transition: background 0.3s ease;
  }

  .timer-circle-inner {
    width: 138px;
    height: 138px;
    border-radius: 50%;
    background: var(--card);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  .timer-time {
    font-size: 36px;
    font-weight: 700;
    color: var(--text);
    font-family: 'Caveat', cursive;
    line-height: 1;
  }

  .timer-label {
    font-size: 11px;
    color: var(--text-light);
    margin-top: 4px;
  }

  .timer-controls {
    display: flex;
    justify-content: center;
    gap: 10px;
    margin-top: 14px;
  }

  .timer-btn {
    border: none;
    border-radius: 10px;
    padding: 8px 18px;
    font-family: 'LXGW WenKai', serif;
    font-size: 13px;
    cursor: pointer;
    transition: all 0.2s;
  }

  .timer-btn.start {
    background: var(--accent);
    color: white;
  }
  .timer-btn.start:hover { background: var(--accent-dark); }

  .timer-btn.reset {
    background: var(--cream-light);
    color: var(--accent);
  }
  .timer-btn.reset:hover { background: var(--cream); }

  /* ─── Diary ─── */
  .diary-textarea {
    width: 100%;
    min-height: 140px;
    border: 1.5px solid var(--cream);
    border-radius: 12px;
    padding: 12px;
    font-family: 'LXGW WenKai', serif;
    font-size: 13px;
    color: var(--text);
    resize: vertical;
    outline: none;
    background: var(--bg);
    line-height: 1.8;
    transition: border-color 0.3s;
  }

  .diary-textarea:focus { border-color: var(--accent-light); }

  .diary-textarea::placeholder { color: var(--text-light); opacity: 0.7; }

  .diary-footer {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 10px;
  }

  .char-count { font-size: 12px; color: var(--text-light); }

  .diary-save {
    background: var(--accent);
    color: white;
    border: none;
    border-radius: 10px;
    padding: 7px 16px;
    font-family: 'LXGW WenKai', serif;
    font-size: 13px;
    cursor: pointer;
    transition: all 0.2s;
  }
  .diary-save:hover { background: var(--accent-dark); }

  /* ─── Calendar ─── */
  .calendar-card { grid-column: 1 / -1; }

  .cal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
  }

  .cal-nav {
    background: none;
    border: 1.5px solid var(--cream);
    border-radius: 8px;
    padding: 3px 10px;
    cursor: pointer;
    font-family: 'LXGW WenKai', serif;
    font-size: 13px;
    color: var(--text-light);
    transition: all 0.2s;
  }
  .cal-nav:hover { border-color: var(--accent); color: var(--accent); }

  .cal-month {
    font-size: 15px;
    font-weight: 700;
    color: var(--text);
  }

  .cal-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 4px;
    text-align: center;
  }

  .cal-weekday {
    font-size: 11px;
    color: var(--text-light);
