  }

  .cal-summary span { color: var(--accent); font-weight: 700; }

  /* ─── History ─── */
  .history-card { grid-column: 1 / -1; }

  .entries-list { max-height: 300px; overflow-y: auto; }

  .entry-item {
    display: flex;
    align-items: flex-start;
    gap: 10px;
