    border-bottom: 1px solid var(--cream-light);
    font-size: 13px;
  }

  .entry-item:last-child { border-bottom: none; }
  .entry-time { font-size: 11px; color: var(--text-light); white-space: nowrap; margin-top: 1px; }
  .entry-content { flex: 1; line-height: 1.6; }
  .entry-points { font-size: 12px; color: var(--accent); font-weight: 700; white-space: nowrap; }

  .empty-state {
    text-align: center;
    padding: 24px 0;
    color: var(--text-light);
    font-size: 13px;
    line-height: 1.8;
  }

  /* ─── Export ─── */
  .export-bar {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    margin-bottom: 16px;
  }

  .export-btn {
    background: var(--card);
    border: 1.5px solid var(--cream);
    border-radius: 10px;
    padding: 6px 14px;
    font-family: 'LXGW WenKai', serif;
    font-size: 12px;
    color: var(--text-light);
    cursor: pointer;
    transition: all 0.2s;
  }
  .export-btn:hover { border-color: var(--accent); color: var(--accent); }

  /* ─── Footer ─── */
  .footer {
    text-align: center;
    padding: 24px 0 12px;
    font-size: 13px;
    color: var(--text-light);
  }

  .footer .heart { color: var(--accent); }

  /* ─── Notification ─── */
  .notification {
    position: fixed;
    top: 20px;
    right: -400px;
    background: var(--card);
    padding: 14px 20px;
    border-radius: 12px;
    box-shadow: 0 4px 20px var(--shadow-hover);
    font-size: 13px;
    color: var(--text);
    max-width: 320px;
    transition: right 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
    z-index: 100;
    border-left: 3px solid var(--accent);
  }

  .notification.show { right: 20px; }

  /* ─── Animations ─── */
  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-5px); }
  }

  @keyframes celebrate {
    0% { transform: scale(1); }
    50% { transform: scale(1.08); }
    100% { transform: scale(1); }
  }

  .celebrate { animation: celebrate 0.5s ease; }

  /* ─── Scrollbar ─── */
  .entries-list::-webkit-scrollbar { width: 4px; }
  .entries-list::-webkit-scrollbar-track { background: var(--cream-light); border-radius: 4px; }
  .entries-list::-webkit-scrollbar-thumb { background: var(--cream); border-radius: 4px; }

  /* ─── Responsive ─── */
  @media (max-width: 640px) {
    .points-bar { padding: 12px 14px; }
    .points-num { font-size: 22px; }
    .card { padding: 16px; }
    .timer-circle { width: 140px; height: 140px; }
    .timer-circle-inner { width: 120px; height: 120px; }
    .timer-time { font-size: 30px; }
    .cal-summary { flex-wrap: wrap; gap: 8px; }
  }
</style>
</head>
<body>

<div class="container">
  <!-- Header -->
  <div class="header">
    <div class="mascot-wrap">
      <svg width="48" height="44" viewBox="0 0 48 44" fill="none" xmlns="http://www.w3.org/2000/svg">
